import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { useAuthStore } from "@/stores/auth.store";
import { SubmitHandler, useForm } from "react-hook-form";
import { ProfileUpdatePayload } from "../types/profile.types";

export function PersonalInformationsForm() {
  const { user } = useAuthStore();

  const form = useForm<ProfileUpdatePayload>({
    defaultValues: {
      name: user?.name,
      email: user?.email,
    },
  });

  const handleSubmit: SubmitHandler<ProfileUpdatePayload> = async (
    values,
  ) => {};

  return (
    <Form {...form}>
      <form
        id="createDepartmentForm"
        onSubmit={form.handleSubmit(handleSubmit)}
        className="space-y-6 mt-3 mb-2"
      >
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <FormField
            control={form.control}
            name="name"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Name</FormLabel>
                <FormControl>
                  <Input {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="email"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Email</FormLabel>
                <FormControl>
                  <Textarea {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />
        </div>
      </form>
    </Form>
  );
}
